\begin{theorem}
Let $T$ be a connected simple graph of order $n$.
Then $T$ is a tree {{Iff}} the size of $T$ is $n-1$.
\end{theorem}

\begin{theorem}
Every non-edgeless finite tree has at least two leaf nodes.
\end{theorem}

\begin{theorem}
Let $T$ be a tree of order $n$.
Then the size of $T$ is $n-1$.
\end{theorem}
